patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..bde5f5421352 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3150,6 +3150,38 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  // Look for: select(select(C0, X, false), T, select(C0, A, B))
+  //      -> select(C0, select(X, T, A), B)
+  if (SelectInst *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    if (match(CondSI->getFalseValue(), m_Zero())) {
+      if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+        if ((CondSI->hasOneUse() || FalseSI->hasOneUse()) &&
+            CondSI->getCondition() == FalseSI->getCondition() &&
+            CondSI->getCondition()->getType() == CondVal->getType()) {
+          Value *NewSel = Builder.CreateSelect(CondSI->getTrueValue(), TrueVal,
+                                               FalseSI->getTrueValue());
+          return SelectInst::Create(CondSI->getCondition(), NewSel,
+                                    FalseSI->getFalseValue());
+        }
+      }
+    }
+    // Look for: select(select(C0, true, X), select(C0, A, B), F)
+    //      -> select(C0, A, select(X, B, F))
+    if (match(CondSI->getTrueValue(), m_One())) {
+      if (SelectInst *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
+        if ((CondSI->hasOneUse() || TrueSI->hasOneUse()) &&
+            CondSI->getCondition() == TrueSI->getCondition() &&
+            CondSI->getCondition()->getType() == CondVal->getType()) {
+          Value *NewSel = Builder.CreateSelect(CondSI->getFalseValue(),
+                                               TrueSI->getFalseValue(),
+                                               FalseVal);
+          return SelectInst::Create(CondSI->getCondition(),
+                                    TrueSI->getTrueValue(), NewSel);
+        }
+      }
+    }
+  }
+
   auto canMergeSelectThroughBinop = [](BinaryOperator *BO) {
     // The select might be preventing a division by 0.
     switch (BO->getOpcode()) {

